\n-- Ensure payment_history table has all needed columns\nDO $$\nBEGIN\n  -- method column\n  IF NOT EXISTS (\n    SELECT 1 FROM information_schema.columns\n    WHERE table_name='payment_history' AND column_name='method'\n  ) THEN\n    ALTER TABLE public.payment_history ADD COLUMN method text;\n  END IF;\n\n  -- currency column\n  IF NOT EXISTS (\n    SELECT 1 FROM information_schema.columns\n    WHERE table_name='payment_history' AND column_name='currency'\n  ) THEN\n    ALTER TABLE public.payment_history ADD COLUMN currency text DEFAULT 'usd';\n  END IF;\n\n  -- amount_cop column\n  IF NOT EXISTS (\n    SELECT 1 FROM information_schema.columns\n    WHERE table_name='payment_history' AND column_name='amount_cop'\n  ) THEN\n    ALTER TABLE public.payment_history ADD COLUMN amount_cop numeric;\n  END IF;\n\n  -- event_type column (used in Dashboard cancel)\n  IF NOT EXISTS (\n    SELECT 1 FROM information_schema.columns\n    WHERE table_name='payment_history' AND column_name='event_type'\n  ) THEN\n    ALTER TABLE public.payment_history ADD COLUMN event_type text;\n  END IF;\n\n  -- notes column\n  IF NOT EXISTS (\n    SELECT 1 FROM information_schema.columns\n    WHERE table_name='payment_history' AND column_name='notes'\n  ) THEN\n    ALTER TABLE public.payment_history ADD COLUMN notes text;\n  END IF;\nEND $$;\n